library(arframe)
library(pharmaverseadam)
library(dplyr, warn.conflicts = FALSE)
library(tidyr)
library(cards)

adsl_saf &lt;- pharmaverseadam::adsl |&gt;
  blank_to_na() |&gt;
  filter(SAFFL == "Y", TRT01A != "Screen Failure")

# Prior medications: PREFL == "Y", exclude UNCODED
adcm_prior &lt;- pharmaverseadam::adcm |&gt;
  blank_to_na() |&gt;
  filter(SAFFL == "Y", PREFL == "Y", !is.na(CMCLAS), CMCLAS != "UNCODED")

arm_levels &lt;- c("Placebo", "Xanomeline Low Dose", "Xanomeline High Dose")
arm_n &lt;- adsl_saf |&gt;
  filter(TRT01A %in% arm_levels) |&gt;
  count(TRT01A) |&gt; pull(n, name = TRT01A)
arm_n &lt;- arm_n[arm_levels]
N_total &lt;- nrow(adsl_saf)
n_vec &lt;- c(arm_n, Total = N_total)

Data Preparation

dplyrcards



n_pct &lt;- function(n, denom) sprintf("%d (%.1f)", n, n / denom * 100)

# ── Overall row ──
any_prior_arm &lt;- adcm_prior |&gt;
  distinct(USUBJID, TRT01A) |&gt;
  count(TRT01A) |&gt;
  filter(TRT01A %in% arm_levels) |&gt;
  mutate(value = mapply(n_pct, n, arm_n[TRT01A])) |&gt;
  select(TRT01A, value) |&gt;
  pivot_wider(names_from = TRT01A, values_from = value)

any_prior_total &lt;- n_distinct(adcm_prior$USUBJID)

any_prior_row &lt;- bind_cols(
  tibble(cls = "ANY PRIOR MEDICATION", drug = "ANY PRIOR MEDICATION",
         row_type = "overall"),
  any_prior_arm,
  tibble(Total = n_pct(any_prior_total, N_total))
)

# ── Class-level (CMCLAS) ──
cls_arm &lt;- adcm_prior |&gt;
  distinct(USUBJID, TRT01A, CMCLAS) |&gt;
  count(TRT01A, CMCLAS) |&gt;
  filter(TRT01A %in% arm_levels) |&gt;
  mutate(value = mapply(n_pct, n, arm_n[TRT01A])) |&gt;
  select(TRT01A, CMCLAS, value) |&gt;
  pivot_wider(names_from = TRT01A, values_from = value)

cls_total &lt;- adcm_prior |&gt;
  distinct(USUBJID, CMCLAS) |&gt;
  count(CMCLAS) |&gt;
  mutate(Total = n_pct(n, N_total)) |&gt;
  select(CMCLAS, Total)

cls_wide &lt;- left_join(cls_arm, cls_total, by = "CMCLAS") |&gt;
  mutate(cls = CMCLAS, drug = CMCLAS, row_type = "class", .before = 1) |&gt;
  select(-CMCLAS)

# ── Drug-level (CMDECOD) ──
drug_arm &lt;- adcm_prior |&gt;
  distinct(USUBJID, TRT01A, CMCLAS, CMDECOD) |&gt;
  count(TRT01A, CMCLAS, CMDECOD) |&gt;
  filter(TRT01A %in% arm_levels) |&gt;
  mutate(value = mapply(n_pct, n, arm_n[TRT01A])) |&gt;
  select(TRT01A, CMCLAS, CMDECOD, value) |&gt;
  pivot_wider(names_from = TRT01A, values_from = value)

drug_total &lt;- adcm_prior |&gt;
  distinct(USUBJID, CMCLAS, CMDECOD) |&gt;
  count(CMCLAS, CMDECOD) |&gt;
  mutate(Total = n_pct(n, N_total)) |&gt;
  select(CMCLAS, CMDECOD, Total)

drug_wide &lt;- left_join(drug_arm, drug_total, by = c("CMCLAS", "CMDECOD")) |&gt;
  mutate(cls = CMCLAS, drug = CMDECOD, row_type = "drug", .before = 1) |&gt;
  select(-CMCLAS, -CMDECOD)

# ── Sort: class alphabetical, drugs within class by frequency ──
cls_order &lt;- sort(unique(cls_wide$cls))

prior_med_wide &lt;- bind_rows(
  any_prior_row,
  bind_rows(lapply(cls_order, function(c) {
    bind_rows(
      filter(cls_wide, cls == c),
      filter(drug_wide, cls == c) |&gt;
        left_join(
          adcm_prior |&gt; distinct(USUBJID, CMCLAS, CMDECOD) |&gt;
            count(CMCLAS, CMDECOD, name = "drug_n"),
          by = c("cls" = "CMCLAS", "drug" = "CMDECOD")
        ) |&gt; arrange(desc(drug_n)) |&gt; select(-drug_n)
    )
  }))
) |&gt;
  mutate(across(where(is.character) & !c(cls, drug, row_type),
                ~ replace_na(.x, "0 (0.0)")))




prior_ard &lt;- ard_stack_hierarchical(
  data        = adcm_prior,
  variables   = c(CMCLAS, CMDECOD),
  by          = TRT01A,
  denominator = adsl_saf,
  id          = USUBJID,
  overall     = TRUE,
  over_variables = TRUE
) |&gt;
  sort_ard_hierarchical(sort = "descending")

prior_med_cards &lt;- fr_wide_ard(
  prior_ard,
  statistic = "{n} ({p}%)",
  decimals  = c(p = 1),
  label     = c(
    "..ard_hierarchical_overall.." = "ANY PRIOR MEDICATION",
    CMCLAS  = "Medication Class",
    CMDECOD = "Preferred Name"
  )
)

arframe Pipeline

prior_med_wide |&gt;
  fr_table() |&gt;
  fr_titles(
    "Table 14.1.8",
    "Summary of Prior Medications",
    "by Medication Class and Preferred Name",
    "Safety Population"
  ) |&gt;
  fr_cols(
    cls      = fr_col(visible = FALSE),
    drug     = fr_col("Medication Class\n  Preferred Name", width = 3.5),
    row_type = fr_col(visible = FALSE),
    !!!setNames(
      lapply(arm_levels, function(a) fr_col(a, align = "decimal")),
      arm_levels
    ),
    Total = fr_col("Total", align = "decimal"),
    .n = n_vec
  ) |&gt;
  fr_header(bold = TRUE, align = "center") |&gt;
  fr_rows(group_by = "cls", indent_by = "drug") |&gt;
  fr_styles(
    fr_row_style(rows = fr_rows_matches("row_type", value = "class"), bold = TRUE),
    fr_row_style(rows = fr_rows_matches("row_type", value = "overall"), bold = TRUE)
  ) |&gt;
  fr_footnotes(
    "Prior medication: any medication started before first dose of study drug.",
    "Subjects counted once per medication class and once per preferred name.",
    "Percentages based on N per treatment arm (Safety Population).",
    "UNCODED medications excluded."
  )

Data Preparation

dplyrcards



# ── Worst post-baseline toxicity grade per subject per PARAMCD ──
# ATOXGR uses signed values: positive = high direction, negative = low direction
# Worst = maximum absolute toxicity grade
worst_tox &lt;- adlb_saf |&gt;
  filter(is.na(ABLFL) | ABLFL != "Y", !is.na(ATOXGR)) |&gt;
  mutate(abs_tox = abs(as.integer(ATOXGR))) |&gt;
  group_by(USUBJID, PARAMCD, PARAM, TRT01A) |&gt;
  slice_max(abs_tox, n = 1, with_ties = FALSE) |&gt;
  ungroup() |&gt;
  mutate(worst_grade = abs_tox)

# Subjects with no post-baseline data get Grade 0 (no abnormality)
all_subj_param &lt;- adlb_saf |&gt;
  filter(ABLFL == "Y") |&gt;
  distinct(USUBJID, PARAMCD, PARAM, TRT01A)

# Fill Grade 0 for subjects with baseline but no post-baseline tox record
worst_tox_full &lt;- all_subj_param |&gt;
  left_join(
    worst_tox |&gt; select(USUBJID, PARAMCD, worst_grade),
    by = c("USUBJID", "PARAMCD")
  ) |&gt;
  mutate(
    worst_grade = replace_na(worst_grade, 0L),
    worst_grade = factor(worst_grade, levels = 0:3)
  )

# ── Grade labels (display grades 0–3) ──
grade_levels &lt;- c("0", "1", "2", "3", "Any Grade &gt;= 1")

n_pct &lt;- function(n, denom) {
  ifelse(denom == 0, "0 (0.0)", sprintf("%d (%.1f)", n, n / denom * 100))
}

# ── Count subjects per worst grade per arm per param ──
grade_counts &lt;- worst_tox_full |&gt;
  filter(TRT01A %in% arm_levels) |&gt;
  count(PARAMCD, PARAM, TRT01A, worst_grade, .drop = FALSE) |&gt;
  filter(!is.na(PARAMCD), !is.na(TRT01A)) |&gt;
  mutate(grade_label = paste0("Grade ", worst_grade))

# Denominators: all subjects with a baseline record for each param×arm
denom_df &lt;- worst_tox_full |&gt;
  filter(TRT01A %in% arm_levels) |&gt;
  count(PARAMCD, TRT01A, name = "denom")

grade_pct &lt;- grade_counts |&gt;
  left_join(denom_df, by = c("PARAMCD", "TRT01A")) |&gt;
  mutate(value = n_pct(n, denom)) |&gt;
  select(PARAMCD, PARAM, grade_label, TRT01A, value) |&gt;
  pivot_wider(names_from = TRT01A, values_from = value)

# ── Any Grade &gt;= 1 derived row ──
any_grade &lt;- worst_tox_full |&gt;
  filter(TRT01A %in% arm_levels, worst_grade &gt;= 1) |&gt;
  count(PARAMCD, PARAM, TRT01A) |&gt;
  left_join(denom_df, by = c("PARAMCD", "TRT01A")) |&gt;
  mutate(
    value       = n_pct(n, denom),
    grade_label = "Any Grade &gt;= 1"
  ) |&gt;
  select(PARAMCD, PARAM, grade_label, TRT01A, value) |&gt;
  pivot_wider(names_from = TRT01A, values_from = value)

# ── Combine grades 0–3 + Any Grade &gt;= 1, sorted by PARAM then grade ──
tox_wide &lt;- bind_rows(grade_pct, any_grade) |&gt;
  mutate(
    PARAMCD = factor(PARAMCD, levels = param_subset),
    grade_order = case_when(
      grade_label == "Grade 0"       ~ 0,
      grade_label == "Grade 1"       ~ 1,
      grade_label == "Grade 2"       ~ 2,
      grade_label == "Grade 3"       ~ 3,
      grade_label == "Any Grade &gt;= 1" ~ 4
    )
  ) |&gt;
  arrange(PARAMCD, grade_order) |&gt;
  mutate(
    PARAMCD     = as.character(PARAMCD),
    is_summary  = if_else(grade_label == "Any Grade &gt;= 1", "summary", "grade")
  ) |&gt;
  mutate(across(all_of(arm_levels), ~ replace_na(.x, "0 (0.0)"))) |&gt;
  select(PARAMCD, PARAM, grade_label, is_summary, all_of(arm_levels))



The worst toxicity grade analysis requires a per-subject maximum derivation before tabulation. This pre-processing step is most naturally expressed in dplyr. The cards path below reuses the derived worst_tox_full dataset from the dplyr tab:

# Reuse worst_tox_full derived above (worst post-baseline grade per subject)
# Tabulate using ard_categorical on the worst_grade variable

tox_ard_data &lt;- worst_tox_full |&gt;
  filter(TRT01A %in% arm_levels) |&gt;
  mutate(
    worst_grade_cat = factor(
      paste0("Grade ", worst_grade),
      levels = c("Grade 0", "Grade 1", "Grade 2", "Grade 3")
    )
  )

# Grade 0-3 counts via dplyr (same derivation, cards-style naming)
tox_cards_grades &lt;- tox_ard_data |&gt;
  count(PARAMCD, PARAM, TRT01A, worst_grade_cat) |&gt;
  left_join(
    tox_ard_data |&gt; count(PARAMCD, TRT01A, name = "denom"),
    by = c("PARAMCD", "TRT01A")
  ) |&gt;
  mutate(
    value      = ifelse(denom == 0, "0 (0.0)", sprintf("%d (%.1f)", n, n / denom * 100)),
    grade_label = as.character(worst_grade_cat)
  ) |&gt;
  select(PARAMCD, PARAM, grade_label, TRT01A, value) |&gt;
  pivot_wider(names_from = TRT01A, values_from = value)

tox_cards_any &lt;- tox_ard_data |&gt;
  filter(worst_grade &gt;= 1) |&gt;
  count(PARAMCD, PARAM, TRT01A) |&gt;
  left_join(
    tox_ard_data |&gt; count(PARAMCD, TRT01A, name = "denom"),
    by = c("PARAMCD", "TRT01A")
  ) |&gt;
  mutate(
    value      = ifelse(denom == 0, "0 (0.0)", sprintf("%d (%.1f)", n, n / denom * 100)),
    grade_label = "Any Grade &gt;= 1"
  ) |&gt;
  select(PARAMCD, PARAM, grade_label, TRT01A, value) |&gt;
  pivot_wider(names_from = TRT01A, values_from = value)

tox_cards &lt;- bind_rows(tox_cards_grades, tox_cards_any) |&gt;
  mutate(
    PARAMCD = factor(PARAMCD, levels = param_subset),
    grade_order = case_when(
      grade_label == "Grade 0"        ~ 0,
      grade_label == "Grade 1"        ~ 1,
      grade_label == "Grade 2"        ~ 2,
      grade_label == "Grade 3"        ~ 3,
      grade_label == "Any Grade &gt;= 1" ~ 4
    )
  ) |&gt;
  arrange(PARAMCD, grade_order) |&gt;
  mutate(
    PARAMCD    = as.character(PARAMCD),
    is_summary = if_else(grade_label == "Any Grade &gt;= 1", "summary", "grade")
  ) |&gt;
  mutate(across(all_of(arm_levels), ~ replace_na(.x, "0 (0.0)"))) |&gt;
  select(PARAMCD, PARAM, grade_label, is_summary, all_of(arm_levels))

