      EOSSTT == "COMPLETED"    ~ "Completed",
      EOSSTT == "DISCONTINUED" ~ "Discontinued",
      is.na(EOSSTT)            ~ "Ongoing",
      TRUE                     ~ EOSSTT
    ),
    disc_reason = case_when(
      disp_status != "Discontinued" ~ NA_character_,
      DTHFL == "Y"                  ~ "Death",
      TRUE                          ~ "Other"
    )
  )

