    mutate(
      n_col   = as.character(n_subj),
      py_col  = sprintf("%.1f", patient_years),
      rate_col = sprintf("%.2f", n_subj / patient_years * 100)
    ) |&gt;
    select(all_of(by_vars), TRT01A, n_col, py_col, rate_col)
}

