      Total    = n_pct(total_n, N_total),
      section  = "Maximum Increase from Baseline",
      category = label,
      .before  = 1
    ) |&gt;
    select(section, category, TRT01A, value, Total) |&gt;
    pivot_wider(names_from = TRT01A, values_from = value)
